// components/fields/Checkboxes.tsx

import React from 'react';
import type {FieldValues} from 'react-hook-form';
import type {ICheckbox, UseFieldLogicElementProps} from "@lmb-it/kitsconcerto-types";
import {Flex, KitsRadios} from "../../../../_compat";
import type {IRadioCheckboxListItem} from "@lmb-it/kitsconcerto-types";

/**
 * Renders a group of checkboxes.

 */
export const Radios = <T extends FieldValues>({
                                                  element,
                                                  control,
                                                  getValues,
                                                  fieldLogic,
                                              }: UseFieldLogicElementProps<T>) => {

    // 1. The central hook provides all the necessary state and resolved props.
    const {
        field,
        fieldState,
        label,
        isDisabled,
        isRequired,
        helperText,
        hideError,
        list,
        attached,
        style: elementStyle,
        slots,
    } = fieldLogic



    // 2. Cast the element to its specific type to access unique properties.
    const checkboxElement = element as ICheckbox<T>;
    const {vertical} = checkboxElement;

    // 3. The component is now only responsible for rendering the UI.
    return (
        <KitsRadios<T>
            // --- Core react-hook-form props ---
            {...field} // Spreads `onChange`, `onBlur`, `value`, `ref`

            onChange={(checked, event)=>{
                field.onChange({
                    target:{
                        value:event.value
                    }
                });
            }}
            // --- Resolved props from useFieldLogic ---
            id={field.name}
            label={label}
            hideError={hideError}
            disabled={isDisabled}
            required={isRequired}
            invalid={fieldState.invalid}
            errors={fieldState.error?.message}
            helperText={helperText}
            item={list as IRadioCheckboxListItem[]}
            attached={attached}
            appearanceMode={vertical ? 'vertical' : 'horizontal'}
            style={elementStyle?.input}
            containerStyle={elementStyle?.container}
            slots={slots}
        />
    );
};

export default Radios;
